import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RecentAddition {
  name: string;
  region: string;
  rating: number;
}

interface RatingsByRegion {
  region: string;
  rating: number;
}

interface WineData {
  collection: {
    totalBottles: number;
    recentAdditions: RecentAddition[];
  };
  ratingsByRegion: RatingsByRegion[];
}

export default function Widget() {
  const wineData = response.data as WineData;
  const { collection, ratingsByRegion } = wineData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFD700', mb: 1 }}>
              Wine Collection
            </Typography>
            <Typography variant="body2" sx={{ color: '#C0C0C0' }}>
              Total Bottles: {collection.totalBottles}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFD700', mb: 1 }}>
              Recent Additions
            </Typography>
            <Stack direction="column" spacing={1}>
              {collection.recentAdditions.map((wine, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                    {wine.name}
                  </Typography>
                  <Typography variant="caption" sx={{ color: '#C0C0C0' }}>
                    {wine.region} - Rating: {wine.rating}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFD700', mb: 1 }}>
              Ratings by Region
            </Typography>
            <BarChart
              height={120}
              series={[
                {
                  data: ratingsByRegion.map(r => r.rating),
                  color: '#B22222',
                },
              ]}
              xAxis={[
                {
                  data: ratingsByRegion.map(r => r.region),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#C0C0C0',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
